   265→class UpstreamRequestFilterManagerCallbacks : public Http::FilterManagerCallbacks,
   266→                                              public Event::DeferredDeletable,
   267→                                              public Http::UpstreamStreamFilterCallbacks {
   268→public:
   269→  UpstreamRequestFilterManagerCallbacks(UpstreamRequest& upstream_request)
   270→      : upstream_request_(upstream_request) {}
   271→  void encodeHeaders(Http::ResponseHeaderMap&, bool end_stream) override {
   272→    upstream_request_.decodeHeaders(std::move(response_headers_), end_stream);
   273→  }
   274→  void encode1xxHeaders(Http::ResponseHeaderMap&) override {
   275→    upstream_request_.decode1xxHeaders(std::move(informational_headers_));
   276→  }
   277→  void encodeData(Buffer::Instance& data, bool end_stream) override {
   278→    upstream_request_.decodeData(data, end_stream);
   279→  }
   280→  void encodeTrailers(Http::ResponseTrailerMap&) override {
   281→    upstream_request_.decodeTrailers(std::move(response_trailers_));
   282→  }
   283→  void encodeMetadata(Http::MetadataMapPtr&& metadata) override {
   284→    upstream_request_.decodeMetadata(std::move(metadata));
   285→  }
   286→  void setRequestTrailers(Http::RequestTrailerMapPtr&& request_trailers) override {
   287→    trailers_ = std::move(request_trailers);
   288→  }
   289→  void setInformationalHeaders(Http::ResponseHeaderMapPtr&& response_headers) override {
   290→    informational_headers_ = std::move(response_headers);
   291→  }
   292→  void setResponseHeaders(Http::ResponseHeaderMapPtr&& response_headers) override {
   293→    response_headers_ = std::move(response_headers);
   294→  }
   295→  void setResponseTrailers(Http::ResponseTrailerMapPtr&& response_trailers) override {
   296→    response_trailers_ = std::move(response_trailers);
   297→  }
   298→  Http::RequestHeaderMapOptRef requestHeaders() override;
   299→  Http::RequestTrailerMapOptRef requestTrailers() override;
   300→  Http::ResponseHeaderMapOptRef informationalHeaders() override {
   301→    if (informational_headers_) {
   302→      return {*informational_headers_};
   303→    }
   304→    return {};
   305→  }
   306→  Http::ResponseHeaderMapOptRef responseHeaders() override {
   307→    if (response_headers_) {
   308→      return {*response_headers_};
   309→    }
   310→    return {};
   311→  }
   312→  Http::ResponseTrailerMapOptRef responseTrailers() override {
   313→    if (response_trailers_) {
   314→      return {*response_trailers_};
   315→    }
   316→    return {};
   317→  }
   318→  // If the filter manager determines a decoder filter has available, tell
   319→  // the router to resume the flow of data from downstream.
