   361→    upstream_request_.dumpState(os, indent_level);
   362→  }
   363→  bool pausedForConnect() const override { return upstream_request_.paused_for_connect_; }
   364→  void setPausedForConnect(bool value) override { upstream_request_.paused_for_connect_ = value; }
   365→
   366→  bool pausedForWebsocketUpgrade() const override {
   367→    return upstream_request_.paused_for_websocket_;
   368→  }
