   165→void UpstreamRequest::cleanUp() {
   166→  if (cleaned_up_) {
   167→    return;
   168→  }
   169→  cleaned_up_ = true;
   170→
   171→  filter_manager_->destroyFilters();
   172→
   173→  if (span_ != nullptr) {
